+        drop(runtime);
+    }));
+    let _ = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
+        crate::runtime_async::clear_runtime_handle();
+    }));
+    if let Err(payload) = result {
+        std::panic::resume_unwind(payload);
+    }
